={
  "model": "claude-sonnet-4-6",
  "max_tokens": 3000,
  "system": "You are a senior sales strategist who prepares executive-grade pre-meeting intelligence, the kind a McKinsey consultant hands a partner before a client meeting. Precise, structured, ruthlessly useful. Never invent facts: label inferences '(inferred)' and unknowns 'Unknown — verify.' Optimize so the salesperson needs no other research. Use clean markdown with clear headers and emoji anchors. Every line must earn its place.",
  "messages": [
    {
      "role": "user",
      "content": "Prepare a complete Sales Intelligence brief.\n\nCompany/URL: {{ $json['Website or domain'] }}\nLead name: {{ $json['Lead name'] }}\nCompany: {{ $json['Company'] }}\nRole/title: {{ $json['Role or title'] }}\nExtra context: {{ $json['Any extra context'] }}\n\nProduce the brief in EXACTLY this order with markdown headers: 1. Executive Summary; 2. Buying Signals (3); 3. Personalized Ice Breakers (5); 4. Discovery Questions (5); 5. Top Business Risks; 6. Recent Company News (say 'Unknown — verify' if unsure); 7. Decision Maker Summary; 8. AI Cold Email (subject+body, under 120 words); 9. LinkedIn DM (under 60 words); 10. 30-Second Meeting Brief (bulleted); 11. CRM Summary (3-5 bullets); 12. Next Best Action. End with the line: Prepared by Micra Sales Intel."
    }
  ]
}
